<?php
namespace App\Modules\Hr\Performance\Models;
use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use App\Modules\Hr\Performance\Enums\PerformanceEvaluationStatus; use App\Modules\Hr\Performance\Enums\ReviewerType; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class HrPerformanceEvaluation extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','cycle_id','template_id','employee_id','reviewer_employee_id','reviewer_type','answers','overall_score','status','submitted_at','calibrated_score','calibration_note','calibrated_by','calibrated_at']; protected function casts():array{return ['answers'=>'array','overall_score'=>'decimal:2','reviewer_type'=>ReviewerType::class,'status'=>PerformanceEvaluationStatus::class,'submitted_at'=>'datetime','calibrated_score'=>'decimal:2','calibrated_at'=>'datetime'];} public function cycle():BelongsTo{return $this->belongsTo(HrPerformanceCycle::class,'cycle_id');} public function template():BelongsTo{return $this->belongsTo(HrPerformanceTemplate::class,'template_id');} public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);} public function reviewer():BelongsTo{return $this->belongsTo(HrEmployee::class,'reviewer_employee_id');} }
